// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title  OracleGovernanceToken
/// @notice ERC20 governance token for LocalOracle.
///
///         Holders vote on oracle parameters: weather-data sources, stake caps,
///         adjudication weights, and fee splits.
///
///         Total supply : 1,000,000 LOG (18 decimals), minted to this contract.
///         Distribution :
///           • Market creators receive `creatorReward` LOG on market creation.
///           • Participants receive 1 LOG per 1 USDC staked (capped at
///             `participantRewardCap`) when they claim a payout.
///
///         The `distributor` address (set to the PredictionMarket contract by the
///         owner) is the only account allowed to trigger reward transfers.
contract OracleGovernanceToken {
    // ─── ERC20 Storage ───────────────────────────────────────────────────────
    string  public constant name     = "LocalOracle Governance";
    string  public constant symbol   = "LOG";
    uint8   public constant decimals = 18;

    uint256 public totalSupply;
    mapping(address => uint256)                     public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    // ─── Governance Parameters ───────────────────────────────────────────────
    address public owner;
    address public distributor; // PredictionMarket contract address

    uint256 public constant TOTAL_SUPPLY = 1_000_000e18; // 1 M LOG

    /// @notice Flat LOG reward per market created (default: 100 LOG).
    uint256 public creatorReward = 100e18;

    /// @notice Maximum LOG reward per payout claim (default: 100 LOG).
    ///         Actual amount scales 1 LOG per 1 USDC staked up to this cap.
    uint256 public participantRewardCap = 100e18;

    // ─── ERC20 Events ────────────────────────────────────────────────────────
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    // ─── Governance Events ───────────────────────────────────────────────────
    event DistributorSet(address indexed distributor);
    event CreatorRewarded(address indexed creator, uint256 indexed marketId, uint256 amount);
    event ParticipantRewarded(address indexed participant, uint256 indexed marketId, uint256 amount);
    event RewardParamsUpdated(uint256 creatorReward, uint256 participantRewardCap);

    // ─── Errors ──────────────────────────────────────────────────────────────
    error Unauthorized();
    error InsufficientBalance();
    error InsufficientAllowance();
    error InsufficientRewardPool();
    error ZeroAddress();

    // ─── Constructor ─────────────────────────────────────────────────────────
    constructor() {
        owner = msg.sender;
        // Entire supply held by this contract; distributed via reward calls.
        _mint(address(this), TOTAL_SUPPLY);
    }

    // ─── ERC20 Core ──────────────────────────────────────────────────────────
    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        if (allowed != type(uint256).max) {
            if (allowed < amount) revert InsufficientAllowance();
            allowance[from][msg.sender] = allowed - amount;
        }
        _transfer(from, to, amount);
        return true;
    }

    // ─── Distribution ────────────────────────────────────────────────────────

    /// @notice Reward a market creator with a flat LOG grant.
    ///         Called by PredictionMarket inside createMarket().
    /// @param creator   Address of the market creator.
    /// @param marketId  ID of the newly created market (for event indexing).
    function rewardCreator(address creator, uint256 marketId) external onlyDistributor {
        uint256 amount = creatorReward;
        if (balanceOf[address(this)] < amount) revert InsufficientRewardPool();
        _transfer(address(this), creator, amount);
        emit CreatorRewarded(creator, marketId, amount);
    }

    /// @notice Reward a participant proportional to their winning stake.
    ///         Rate: 1 LOG per 1 USDC (6-decimal) staked, capped at
    ///         `participantRewardCap`.
    ///         Called by PredictionMarket inside claimPayout().
    /// @param participant  Address claiming the payout.
    /// @param marketId     Market the payout was claimed from.
    /// @param stakeAmount  Winning stake in USDC (6 decimals).
    function rewardParticipant(
        address participant,
        uint256 marketId,
        uint256 stakeAmount
    ) external onlyDistributor {
        // 1 LOG (1e18) per 1 USDC (1e6) → multiply by 1e12
        uint256 amount = stakeAmount * 1e12;
        if (amount > participantRewardCap) amount = participantRewardCap;
        if (amount == 0) amount = 1e18; // minimum 1 LOG for any participation
        if (balanceOf[address(this)] < amount) revert InsufficientRewardPool();
        _transfer(address(this), participant, amount);
        emit ParticipantRewarded(participant, marketId, amount);
    }

    // ─── Admin ───────────────────────────────────────────────────────────────

    /// @notice Designate the contract that may trigger reward distribution.
    ///         Should be set to the deployed PredictionMarket address.
    function setDistributor(address _distributor) external onlyOwner {
        if (_distributor == address(0)) revert ZeroAddress();
        distributor = _distributor;
        emit DistributorSet(_distributor);
    }

    /// @notice Adjust reward parameters (e.g. after governance vote off-chain).
    function setRewardParams(
        uint256 _creatorReward,
        uint256 _participantRewardCap
    ) external onlyOwner {
        creatorReward        = _creatorReward;
        participantRewardCap = _participantRewardCap;
        emit RewardParamsUpdated(_creatorReward, _participantRewardCap);
    }

    /// @notice Transfer unsold/reserve tokens to owner (e.g. for DAO treasury).
    function withdrawReserve(uint256 amount) external onlyOwner {
        _transfer(address(this), owner, amount);
    }

    // ─── Modifiers ───────────────────────────────────────────────────────────
    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    /// @dev Owner can also call distribution functions directly (e.g. manual airdrops).
    modifier onlyDistributor() {
        if (msg.sender != distributor && msg.sender != owner) revert Unauthorized();
        _;
    }

    // ─── Internal ────────────────────────────────────────────────────────────
    function _transfer(address from, address to, uint256 amount) internal {
        if (balanceOf[from] < amount) revert InsufficientBalance();
        unchecked {
            balanceOf[from] -= amount;
            balanceOf[to]   += amount;
        }
        emit Transfer(from, to, amount);
    }

    function _mint(address to, uint256 amount) internal {
        totalSupply       += amount;
        balanceOf[to]     += amount;
        emit Transfer(address(0), to, amount);
    }
}

contracts/PredictionMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IWorldID.sol";
import "./interfaces/IERC20.sol";
import "./OracleGovernanceToken.sol";

contract PredictionMarket {
    // ─── Types ───────────────────────────────────────────────────────────
    struct Market {
        uint256 id;
        address creator;
        string question;
        int256 lat;   // latitude * 1e6
        int256 lng;   // longitude * 1e6
        uint256 endTime;
        bool resolved;
        bool outcome; // true = YES won
        uint256 totalYesStake;
        uint256 totalNoStake;
    }

    struct Position {
        uint256 yesAmount;
        uint256 noAmount;
        bool claimed;
    }

    // ─── State ───────────────────────────────────────────────────────────
    IWorldID public immutable worldId;
    IERC20 public immutable usdc;
    address public owner;
    address public oracle;

    OracleGovernanceToken public governanceToken; // optional; address(0) = disabled

    uint256 public nextMarketId;
    uint256 public constant MAX_STAKE_PER_HUMAN = 100e6; // 100 USDC (6 decimals)

    mapping(uint256 => Market) public markets;
    // marketId => nullifierHash => Position
    mapping(uint256 => mapping(uint256 => Position)) public positions;
    // Registered AI agents that may bet without WorldID proof
    mapping(address => bool) public registeredAgents;

    // ─── Events ──────────────────────────────────────────────────────────
    event MarketCreated(uint256 indexed marketId, address creator, string question, int256 lat, int256 lng, uint256 endTime);
    event BetPlaced(uint256 indexed marketId, uint256 nullifierHash, bool isYes, uint256 amount);
    event MarketResolved(uint256 indexed marketId, bool outcome);
    event PayoutClaimed(uint256 indexed marketId, uint256 nullifierHash, uint256 amount);
    event AgentRegistered(address indexed agent);

    // ─── Errors ──────────────────────────────────────────────────────────
    error MarketDoesNotExist();
    error MarketAlreadyResolved();
    error MarketNotResolved();
    error MarketNotEnded();
    error MarketEnded();
    error StakeExceedsMax();
    error AlreadyClaimed();
    error NoPayout();
    error Unauthorized();
    error ZeroAmount();

    // ─── Constructor ─────────────────────────────────────────────────────
    constructor(address _worldId, address _usdc) {
        worldId = IWorldID(_worldId);
        usdc = IERC20(_usdc);
        owner = msg.sender;
        oracle = msg.sender; // owner is oracle by default
    }

    // ─── Modifiers ───────────────────────────────────────────────────────
    modifier onlyOwnerOrOracle() {
        if (msg.sender != owner && msg.sender != oracle) revert Unauthorized();
        _;
    }

    // ─── Market Management ───────────────────────────────────────────────
    function createMarket(
        string calldata question,
        int256 lat,
        int256 lng,
        uint256 endTime
    ) external returns (uint256 marketId) {
        require(endTime > block.timestamp, "End time must be in the future");

        marketId = nextMarketId++;
        markets[marketId] = Market({
            id: marketId,
            creator: msg.sender,
            question: question,
            lat: lat,
            lng: lng,
            endTime: endTime,
            resolved: false,
            outcome: false,
            totalYesStake: 0,
            totalNoStake: 0
        });

        emit MarketCreated(marketId, msg.sender, question, lat, lng, endTime);

        // Reward market creator with LOG (non-blocking: ignore if pool exhausted)
        if (address(governanceToken) != address(0)) {
            try governanceToken.rewardCreator(msg.sender, marketId) {} catch {}
        }
    }

    // ─── Betting (WorldID-verified) ──────────────────────────────────────
    function placeBet(
        uint256 marketId,
        bool isYes,
        uint256 amount,
        uint256 root,
        uint256 nullifierHash,
        uint256[8] calldata proof
    ) external {
        if (amount == 0) revert ZeroAmount();
        Market storage market = markets[marketId];
        if (market.endTime == 0) revert MarketDoesNotExist();
        if (market.resolved) revert MarketAlreadyResolved();
        if (block.timestamp >= market.endTime) revert MarketEnded();

        // Verify WorldID proof on-chain
        worldId.verifyProof(
            root,
            1, // groupId: Orb verification
            uint256(uint160(msg.sender)), // signal = wallet address
            nullifierHash,
            uint256(keccak256(abi.encodePacked("app_localoracle", "place-bet"))),
            proof
        );

        // Check stake cap per human per market
        Position storage pos = positions[marketId][nullifierHash];
        uint256 totalStake = pos.yesAmount + pos.noAmount + amount;
        if (totalStake > MAX_STAKE_PER_HUMAN) revert StakeExceedsMax();

        // Transfer USDC from user
        usdc.transferFrom(msg.sender, address(this), amount);

        // Update position and market totals
        if (isYes) {
            pos.yesAmount += amount;
            market.totalYesStake += amount;
        } else {
            pos.noAmount += amount;
            market.totalNoStake += amount;
        }

        emit BetPlaced(marketId, nullifierHash, isYes, amount);
    }

    // ─── Resolution ──────────────────────────────────────────────────────
    function resolveMarket(uint256 marketId, bool outcome) external onlyOwnerOrOracle {
        _resolveMarketInternal(marketId, outcome);
    }

    /// @notice Called by Chainlink CRE writeReport to settle a market on-chain.
    /// @dev CRE encodes the payload as abi.encodeWithSelector(resolveMarket.selector, marketId, outcome).
    ///      Skip the 4-byte selector prefix and decode the remaining (uint256 marketId, bool outcome).
    function onReport(bytes calldata /* metadata */, bytes calldata report) external {
        bytes calldata payload = report.length > 4 ? report[4:] : report;
        (uint256 marketId, bool outcome) = abi.decode(payload, (uint256, bool));
        _resolveMarketInternal(marketId, outcome);
    }

    function _resolveMarketInternal(uint256 marketId, bool outcome) internal {
        Market storage market = markets[marketId];
        if (market.endTime == 0) revert MarketDoesNotExist();
        if (market.resolved) revert MarketAlreadyResolved();
        if (block.timestamp < market.endTime) revert MarketNotEnded();

        market.resolved = true;
        market.outcome = outcome;

        emit MarketResolved(marketId, outcome);
    }

    // ─── Payouts ─────────────────────────────────────────────────────────
    function claimPayout(uint256 marketId, uint256 nullifierHash) external {
        Market storage market = markets[marketId];
        if (!market.resolved) revert MarketNotResolved();

        Position storage pos = positions[marketId][nullifierHash];
        if (pos.claimed) revert AlreadyClaimed();

        uint256 winnerStake = market.outcome ? pos.yesAmount : pos.noAmount;
        if (winnerStake == 0) revert NoPayout();

        uint256 totalWinPool = market.outcome ? market.totalYesStake : market.totalNoStake;
        uint256 totalLosePool = market.outcome ? market.totalNoStake : market.totalYesStake;

        // Payout = original stake + proportional share of losing pool
        uint256 payout = winnerStake + (winnerStake * totalLosePool / totalWinPool);

        pos.claimed = true;
        usdc.transfer(msg.sender, payout);

        emit PayoutClaimed(marketId, nullifierHash, payout);

        // Reward winning participant with LOG (non-blocking: ignore if pool exhausted)
        if (address(governanceToken) != address(0)) {
            try governanceToken.rewardParticipant(msg.sender, marketId, winnerStake) {} catch {}
        }
    }

    // ─── View Functions ──────────────────────────────────────────────────
    function getMarket(uint256 marketId) external view returns (Market memory) {
        return markets[marketId];
    }

    function getPosition(uint256 marketId, uint256 nullifierHash) external view returns (Position memory) {
        return positions[marketId][nullifierHash];
    }

    // ─── Admin ───────────────────────────────────────────────────────────
    function setOracle(address _oracle) external {
        if (msg.sender != owner) revert Unauthorized();
        oracle = _oracle;
    }

    function setGovernanceToken(address _token) external {
        if (msg.sender != owner) revert Unauthorized();
        governanceToken = OracleGovernanceToken(_token);
    }

    function registerAgent(address agent) external {
        if (msg.sender != owner) revert Unauthorized();
        registeredAgents[agent] = true;
        emit AgentRegistered(agent);
    }

    // ─── Agent Betting (no WorldID required) ─────────────────────────────
    /// @notice Registered AI agents may bet without a WorldID proof.
    ///         The agent's own address is used as its nullifier hash so the
    ///         100 USDC stake cap and double-bet protection still apply.
    function placeBetAgent(uint256 marketId, bool isYes, uint256 amount) external {
        if (!registeredAgents[msg.sender]) revert Unauthorized();
        if (amount == 0) revert ZeroAmount();

        Market storage mkt = markets[marketId];
        if (mkt.endTime == 0) revert MarketDoesNotExist();
        if (mkt.resolved)     revert MarketAlreadyResolved();
        if (block.timestamp >= mkt.endTime) revert MarketEnded();

        uint256 nullifier = uint256(uint160(msg.sender));
        Position storage pos = positions[marketId][nullifier];
        uint256 totalStake = pos.yesAmount + pos.noAmount + amount;
        if (totalStake > MAX_STAKE_PER_HUMAN) revert StakeExceedsMax();

        usdc.transferFrom(msg.sender, address(this), amount);

        if (isYes) {
            pos.yesAmount  += amount;
            mkt.totalYesStake += amount;
        } else {
            pos.noAmount   += amount;
            mkt.totalNoStake  += amount;
        }

        emit BetPlaced(marketId, nullifier, isYes, amount);
    }
}

